#include<bits/stdc++.h>
using namespace std;
bool vis[1010][12];
long long a,b,tot,p[1010],dp[1010][12];
long long dfs(long long x,long long lst,bool pre,bool lim)
{
    if(x==0)
    {
        return 1;
    }
    if(!pre&&!lim)
    {
        if(vis[x][lst])
        {
            return dp[x][lst];
        }

    }
    long long ans=0,l=9;
    if(lim)
    {
        l=p[x];
    }
    for(long long i=0;i<=l;i++)
    {
        if(abs(i-lst)>=2||pre)
        {
            ans+=dfs(x-1,i,(pre&&i==0),(lim&&i==l));
        }
    }
    if(!lim&&!pre)
    {
        dp[x][lst]=ans;
        vis[x][lst]=1;
    }
    return ans;
}
long long solve(long long x)
{
    memset(vis,0,sizeof(vis));
    memset(dp,0,sizeof(dp));
    tot=0;
    while(x)
    {
        p[++tot]=x%10;
        x/=10;
    }
    long long ans=dfs(tot,11,true,true);
    return ans;
}
int main()
{
    long long a,b;
    scanf("%lld%lld",&a,&b);
    printf("%lld",solve(b)-solve(a-1));
    return 0;
}
